var hasIncreasingSubarrays = function(nums, k) {
    const n = nums.length;
    function strictlyIncreasing(start, length) {
        for (let i = start; i < start + length - 1; i++) {
            if (nums[i] >= nums[i + 1]) return false;
        }
        return true;
    }
    for (let a = 0; a <= n - 2 * k; a++) {
        if (strictlyIncreasing(a, k) && strictlyIncreasing(a + k, k)) return true;
    }
    return false;
};
